"""
Checkers Game Logic
"""

class Piece:
    def __init__(self, color):
        self.color = color
        self.king = False

    def __repr__(self):
        if self.color == 'black':
            return 'b' if not self.king else 'B'
        else:
            return 'r' if not self.king else 'R'


class Player:
    def __init__(self, color):
        self.color = color
        self.pieces = []

    def add_piece(self, piece):
        self.pieces.append(piece)


class CheckersGame:
    def __init__(self):
        self.board = [[None for _ in range(8)] for _ in range(8)]
        self.players = [Player('black'), Player('red')]
        self.current_player = 0
        self.setup_board()

    def setup_board(self):
        # Place initial pieces
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('black')
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('red')

    def move_piece(self, start, end):
        x1, y1 = start
        x2, y2 = end
        piece = self.board[x1][y1]
        if self.is_valid_move(start, end):
            self.board[x2][y2] = piece
            self.board[x1][y1] = None
            self.check_capture(x2, y2)
            self.current_player = 1 - self.current_player
            return True
        return False

    def check_capture(self, x, y):
        piece = self.board[x][y]
        if piece and not piece.king:
            directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]
            for dx, dy in directions:
                i, j = x + 2 * dx, y + 2 * dy
                if 0 <= i < 8 and 0 <= j < 8 and self.board[i][j] is None and \
                   0 <= x + dx < 8 and 0 <= y + dy < 8 and self.board[x + dx][y + dy] and \
                   self.board[x + dx][y + dy].color != piece.color:
                    self.board[i][j] = Piece(piece.color)
                    self.board[x + dx][y + dx] = None
                    if x == (0 if piece.color == 'black' else 7):
                        self.board[i][j].king = True
                    return

    def king_piece(self, x, y):
        piece = self.board[x][y]
        if piece and not piece.king and ((piece.color == 'black' and x == 0) or (piece.color == 'red' and x == 7)):
            piece.king = True

    def is_valid_move(self, start, end):
        x1, y1 = start
        x2, y2 = end
        piece = self.board[x1][y1]
        if piece and piece.color != (self.players[self.current_player]).color:
            return False
        directions = [(-1, -1), (-1, 1), (1, -1), (1, 1)]
        for dx, dy in directions:
            if x2 == x1 + dx and y2 == y1 + dy:
                if self.board[x2][y2] is None:
                    return True
            elif x2 == x1 + 2 * dx and y2 == y1 + 2 * dy and self.board[x2][y2] is None:
                middle_piece = self.board[x1 + dx][y1 + dy]
                if middle_piece and middle_piece.color != piece.color:
                    return True
        return False

    def check_winner(self):
        black_pieces = sum(1 for row in self.board for col in row if isinstance(col, Piece) and col.color == 'black')
        red_pieces = sum(1 for row in self.board for col in row if isinstance(col, Piece) and col.color == 'red')
        if black_pieces == 0:
            return 'Red wins'
        elif red_pieces == 0:
            return 'Black wins'
        return None


def main():
    game = CheckersGame()
    while True:
        print('\nCurrent board:')
        for row in game.board:
            print(' '.join(str(piece) if piece else '.' for piece in row))
        move_from = input(f"Player {game.current_player + 1}, enter move (from-to): ").split('-')
        start, end = tuple(map(int, move_from[0].strip().split(','))), tuple(map(int, move_from[1].strip().split(',')))
        if game.move_piece(start, end):
            result = game.check_winner()
            if result:
                print(result)
                break


if __name__ == "__main__":
    main()
```

